using Scriptome.Exportacao;
using Scriptome.Infrastructure;
using Scriptome.Infrastructure.Baseline;
using Scriptome.Infrastructure.Interfaces;
using Scriptome.Nucleo;
using Scriptome.Nucleo.Leitores;
using System;
using System.IO;
using System.Linq;

namespace Scriptome
{
    class Program
    {
        static void Main(string[] args)
        {
            Console.ForegroundColor = ConsoleColor.Cyan;
            Console.WriteLine("=========================================================");
            Console.WriteLine("   SCRIPTOME 3.1  |  ARCHITECTURE: DI + STRATEGY         ");
            Console.WriteLine("=========================================================");
            Console.ResetColor();

            string baseDir = AppDomain.CurrentDomain.BaseDirectory;
            string pastaInput = Path.Combine(baseDir, "Data", "Scripts");
            string pastaOutput = Path.Combine(baseDir, "Data", "Output");

#if DEBUG
            Scriptome.Testes.VerificadorLimbic.ExecutarTeste(baseDir);
#endif

            if (!Directory.Exists(pastaInput)) Directory.CreateDirectory(pastaInput);
            if (!Directory.Exists(pastaOutput)) Directory.CreateDirectory(pastaOutput);

            var pipeline = RaizComposicao.ConstruirPipeline(baseDir);
            var leitor = new LeitorFountain();
            var orquestrador = new OrquestradorNucleo(pipeline);

            IExportadorScriptome exportador = new ExportadorExcelModular();

            var arquivos = Directory.GetFiles(pastaInput, "*.fountain");
            Console.WriteLine($"[SISTEMA] {arquivos.Length} roteiros encontrados.\n");

            foreach (var caminhoArquivo in arquivos)
            {
                string nomeFicheiro = Path.GetFileName(caminhoArquivo);
                Console.ForegroundColor = ConsoleColor.White;
                Console.WriteLine($"\n>>> ANALISANDO: {nomeFicheiro.ToUpper()}");
                Console.ResetColor();

                try
                {
                    var roteiro = leitor.Parse(caminhoArquivo);
                    var estatisticas = orquestrador.Processar(roteiro);

                    if (Path.GetFileNameWithoutExtension(caminhoArquivo)
    .Equals("3-BANHO", StringComparison.OrdinalIgnoreCase))
                    {
                        var pastaBaseline = Path.Combine(
                            Directory.GetCurrentDirectory(),
                            "..", "..", "..",
                            "Baselines",
                            "legacy",
                            "3-BANHO");

                        var caminhoJson = Path.Combine(pastaBaseline, "elenco_legacy.json");

                        ExportadorBaselineElencoLegacyJson.Exportar(
                            estatisticas,
                            caminhoJson);

                        Console.WriteLine("[BASELINE] Snapshot LEGADO gerado.");
                    }

                    // ===============================================================
                    // BASELINE ETOGRAMA (Golden Master)
                    // Congela o modelo legado Etograma
                    // ===============================================================
                    if (Path.GetFileNameWithoutExtension(caminhoArquivo)
                        .Equals("3-BANHO", StringComparison.OrdinalIgnoreCase))
                    {
                        Console.WriteLine("[BASELINE] Gerando snapshot estruturado do Etograma...");

                        var pastaBaseline = Path.Combine(
                            Directory.GetCurrentDirectory(),
                            "..", "..", "..",
                            "Baselines",
                            "etograma",
                            "3-BANHO");

                        foreach (var personagem in estatisticas.AnalisePersonagens)
                        {
                            if (personagem.Etograma != null)
                            {
                                var caminhoArquivoBaseline =
                                    Path.Combine(pastaBaseline, $"{personagem.Nome}.json");

                                ExportadorBaselineEtograma.Exportar(
                                    personagem.Etograma,
                                    caminhoArquivoBaseline);
                            }
                        }

                        Console.ForegroundColor = ConsoleColor.Green;
                        Console.WriteLine("[BASELINE] Snapshot 3-BANHO concluído.");
                        Console.ResetColor();


                    }

                    if (estatisticas.AnalisePersonagens == null || !estatisticas.AnalisePersonagens.Any())
                    {
                        Console.ForegroundColor = ConsoleColor.Yellow;
                        Console.WriteLine("[AVISO] Pipeline retornou 0 personagens.");
                        Console.ResetColor();
                    }

                    Console.WriteLine("[FINGERPRINT] Calibrando estatísticas de elenco...");

                    string pastaDestino = Path.Combine(
                        pastaOutput,
                        Path.GetFileNameWithoutExtension(caminhoArquivo));

                    if (!Directory.Exists(pastaDestino))
                    {
                        Directory.CreateDirectory(pastaDestino);
                        Console.WriteLine($"[IO] Pasta criada: {pastaDestino}");
                    }

                    Console.WriteLine($"[EXPORT] Gravando dados via {exportador.Nome} em: {pastaDestino}");

                    exportador.Exportar(estatisticas, pastaDestino);

                    if (Directory.GetFiles(pastaDestino).Length > 0)
                    {
                        Console.ForegroundColor = ConsoleColor.Green;
                        Console.WriteLine("[SUCESSO] Arquivos gerados com sucesso.");
                    }
                    else
                    {
                        Console.ForegroundColor = ConsoleColor.Red;
                        Console.WriteLine("[ALERTA] Nenhum arquivo encontrado na pasta.");
                    }

                    Console.ResetColor();
                }
                catch (Exception ex)
                {
                    Console.ForegroundColor = ConsoleColor.Red;
                    Console.WriteLine($"[FALHA NO PROCESSO] {nomeFicheiro}: {ex.Message}");
                    if (ex.InnerException != null)
                        Console.WriteLine($" -> {ex.InnerException.Message}");
                    Console.ResetColor();
                }
            }

            Console.WriteLine("\n=========================================================");
            Console.WriteLine("   PROCESSO CONCLUÍDO. PRESSIONE QUALQUER TECLA PARA SAIR.");
            Console.WriteLine("=========================================================");
            Console.ReadKey();
        }
    }
}
